/***************************************
 * QAcademy — Quiz Builder API (Clean v1)
 * + Fixed Quizzes (courseQuizzes + fixed.spawn)
 * + attempt.finish (write-back of results)
 * + attempt.update (partial save)
 * + attempts.list (history API)
 * Project Alpha — 2025-11-08 (Europe/London)
 ***************************************/

const PORTAL_DB_ID = '1Aq0IaPOjC1Vo4bQb8aP0S0bO5EaeUx_4oYUlnJ2g2vc'; // Portal DB
const TAB_COURSES  = 'courses';   // columns: course_id, sheet_id, status
const TAB_ATTEMPTS = 'attempts';  // created on first use if missing
const TAB_QUIZZES  = 'quizzes';   // columns: quiz_id, course_id, type, title, published, visibility, publish_at, unpublish_at, n, duration_min, ...
const TAB_USERS        = 'users';
const TAB_TOKENS       = 'tokens';

// NEW:
const TAB_ANNOUNCEMENTS = 'announcements';
const TAB_PRODUCTS      = 'products';
const TAB_SUBSCRIPTIONS = 'subscriptions';
const TAB_PROGRAMS      = 'programs';   // NEW: canonical program list
const TAB_LEVELS        = 'levels';     // NEW: canonical level list
// NEW: per-user state for announcements
const TAB_NOTICE_STATE = 'user_notice_state';

// Must match your sheet columns (final order)
const NOTICE_STATE_HEADER = [
  'user_id',
  'user_label',
  'user_email',
  'item_type',
  'item_id',
  'state',
  'seen_at',
  'updated_at'
];

const NOTICE_ITEM_ANN = 'ANNOUNCEMENT';
const NOTICE_STATE_SEEN = 'seen';
const NOTICE_STATE_DISMISSED = 'dismissed';



// Hard caps / defaults
const MAX_N_DEFAULT = 50; // global cap for spawn requests

// Standard schema for TAB_ATTEMPTS (used by writer + finisher)
// Keep all you might need for history / review / retakes
const ATTEMPTS_DEFAULT_HEADER = [
  'attempt_id',
  'ts_iso',
  'course_id',
  'mode',
  'duration_min',
  'user_id',
  'n',
  'seed',
  'source',
  'item_ids',
  'quiz_id',
  'display_label',
  'status',           // in_progress / completed / abandoned
  'score_raw',
  'score_total',
  'score_pct',
  'time_taken_s',
  'answers_json',
  'origin_attempt_id' // for future "retake based on" linkage
];


const ANNOUNCEMENTS_DEFAULT_HEADER = [
  'announcement_id',
  'title',
  'body_html',
  'body_text',
  'body',
  'status',
  'created_at',
  'start_at',
  'end_at',
  'pinned',
  'priority',
  'dismissible',
  'scope_programs',
  'scope_courses',
  'scope_level',
  'scope_subscription_kind',
  'scope_product_ids',
  'scope_audience',
  'scope_cohort',
  'scope_user_ids'       // 🔹 NEW: user-level targeting
];



/* ==================== HTTP HANDLERS ==================== */
function doGet(e) {
  try {
    const action = (e.parameter.action || '').toLowerCase();

    if (action === 'health') {
      return json_({ ok: true, ts: new Date().toISOString() });
    }

    if (action === 'builder.meta') {
      const courseId = reqParam_(e, 'course_id');
      const meta = getBuilderMeta_(courseId);
      return json_(meta);
    }

    if (action === 'courses') {
      return json_({ courses: listActiveCourses_() });
    }

        if (action === 'users.search') {
      const out = handleUsersSearch_(e);
      return json_(out);
    }


    if (action === 'attempt') {
      const attemptId   = reqParam_(e, 'attempt_id');
      const token       = (e.parameter.token     || '').trim();
      const expectMode  = (e.parameter.mode      || '').trim().toLowerCase();
      const expectCid   = (e.parameter.course_id || '').trim();

      const out = getAttempt_(attemptId, {
        token:            token,
        expectedMode:     expectMode,
        expectedCourseId: expectCid
      });
      return json_(out);
    }


    if (action === 'coursequizzes') {
      const courseId = reqParam_(e, 'course_id');
      const out = getCourseQuizzes_(courseId);
      return json_(out);
    }


    if (action === 'announcements.meta') {
      const token = reqParam_(e, 'token');
      // Just to ensure it's a valid logged-in user; no extra checks here
      verifyToken_(token);

      const meta = getAnnouncementsMeta_();
      return json_(meta);
    }

if (action === 'announcements.list') {
  const token = reqParam_(e, 'token'); // qa_token from browser
  const mode  = (e.parameter.mode || '').trim().toLowerCase(); // '' | 'admin' | 'archive' | 'dashboard'

  const limit = parseInt(e.parameter.limit || '0', 10) || 20;
  const authInfo = verifyToken_(token);
  const userId   = authInfo.user_id;

  if (mode === 'admin') {
    // Admin listing with filters
    const out = listAnnouncementsAdmin_({
      status:           (e.parameter.status           || '').trim(), // CSV: "active,scheduled"
      program_id:       (e.parameter.program_id       || '').trim(),
      course_id:        (e.parameter.course_id        || '').trim(),
      cohort:           (e.parameter.cohort           || '').trim(),
      level:            (e.parameter.level            || '').trim(), // 🔹 NEW
      subscription_kind:(e.parameter.subscription_kind|| '').trim(),
      product_id:       (e.parameter.product_id       || '').trim(),
      audience:         (e.parameter.audience         || '').trim(),
      search:           (e.parameter.search           || '').trim(),
      offset:           parseInt(e.parameter.offset || '0', 10) || 0,
      limit:            limit
    });
    return json_(out);
  } else {
    // Student/dashboard/announcements listing
    const courseId = (e.parameter.course_id || '').trim(); // optional

    // Decide default window based on mode:
    // - dashboard ('' or 'dashboard') → 30 days
    // - archive                       → 730 days (~2 years)
    const rawRecent = (e.parameter.recent_days || '').trim();
    let recentDays;

    if (!rawRecent) {
      recentDays = (mode === 'archive') ? 730 : 30;
    } else {
      recentDays = parseInt(rawRecent, 10);
      if (!recentDays || isNaN(recentDays)) {
        recentDays = (mode === 'archive') ? 730 : 30;
      }
    }

    const out = listAnnouncementsForUser_({
      user_id:     userId,
      course_id:   courseId,
      limit:       limit,
      mode:        mode,        // '' | 'archive' | 'dashboard'
      recent_days: recentDays   // dashboard=30, archive=730 unless overridden
    });
    return json_(out);
  }

}



    // NEW: attempts.list — list attempts for the *current verified user*
    if (action === 'attempts.list') {
      // We now trust ONLY the token, not a user_id from the browser
      const token    = reqParam_(e, 'token');
      const authInfo = verifyToken_(token);  // NEW helper below
      const userId   = authInfo.user_id;

      const courseId = (e.parameter.course_id || '').trim();
      const mode     = (e.parameter.mode     || '').trim();
      const source   = (e.parameter.source   || '').trim();
      const status   = (e.parameter.status   || '').trim();

      const out = listAttempts_({
        user_id:   userId,
        course_id: courseId,
        mode:      mode,
        source:    source,
        status:    status
      });
      return json_(out);
    }
    if (action === 'announcements.states') {
  const token = reqParam_(e, 'token');
  const authInfo = verifyToken_(token);
  const userId = authInfo.user_id;

  const itemIdsCsv = (e.parameter.item_ids || '').trim();
  const itemIds = itemIdsCsv
    ? itemIdsCsv.split(',').map(s => String(s||'').trim()).filter(Boolean)
    : [];

  const out = announcementStates_({ user_id: userId, item_ids: itemIds });
  return json_(out);
}


    return jsonError_('Unknown action', 400);
  } catch (err) {
    return jsonError_(err.message || String(err), 500);
  }
}

function doPost(e) {
  try {
    const action = (e.parameter.action || '').toLowerCase();

    if (action === 'builder.spawn') {
      const raw = e.parameter.payload || (e.postData && e.postData.contents) || '';
      if (!raw) {
        return jsonError_('Missing payload', 400);
      }
      const payload = JSON.parse(raw); // {course_id, topics[], difficulties[], n, mode, source}
      const result  = spawnAttempt_(payload);
      return json_(result);
    }

if (action === 'fixed.spawn') {
  const raw = e.parameter.payload || (e.postData && e.postData.contents) || '';
  if (!raw) return jsonError_('Missing payload', 400);

  const token = (e.parameter.token || '').trim();
  if (!token) return jsonError_('Missing token', 400);

  const authInfo = verifyToken_(token);
  const payload = JSON.parse(raw); // {quiz_id, source?}

  // ✅ enforce owner from token
  payload.user_id = authInfo.user_id;

  const result = spawnFixedAttempt_(payload);
  return json_(result);
}


    // attempt.finish — write back score + timing + answers
    if (action === 'attempt.finish') {
      const raw = e.parameter.payload || (e.postData && e.postData.contents) || '';
      if (!raw) {
        return jsonError_('Missing payload', 400);
      }
      const payload = JSON.parse(raw); // {attempt_id, score_*, time_taken_s, answers[]}
      const result  = finishAttempt_(payload);
      return json_(result);
    }

    // attempt.update — partial save while in_progress
    if (action === 'attempt.update') {
      const raw = e.parameter.payload || (e.postData && e.postData.contents) || '';
      if (!raw) {
        return jsonError_('Missing payload', 400);
      }
      const payload = JSON.parse(raw); // {attempt_id, answers:[], time_taken_s?}
      const result  = updateAttempt_(payload);
      return json_(result);
    }

    // attempt.retake — create a new attempt with SAME questions
if (action === 'attempt.retake') {
  const raw = e.parameter.payload || (e.postData && e.postData.contents) || '';
  if (!raw) return jsonError_('Missing payload', 400);

  const token = (e.parameter.token || '').trim();
  if (!token) return jsonError_('Missing token', 400);

  const authInfo = verifyToken_(token);
  const payload = JSON.parse(raw); // {attempt_id}

  payload.user_id = authInfo.user_id;

  const result = retakeAttempt_(payload);
  return json_(result);
}


    // NEW: announcements.save — create or update an announcement (ADMIN ONLY)
    if (action === 'announcements.save') {
      const raw   = e.parameter.payload || (e.postData && e.postData.contents) || '';
      const token = (e.parameter.token || '').trim();

      if (!raw) {
        return jsonError_('Missing payload', 400);
      }
      if (!token) {
        return jsonError_('Missing token', 400);
      }

      const payload = JSON.parse(raw);
      const result  = saveAnnouncementFromAdmin_(token, payload);
      return json_(result);
    }

// ✅ EXPLICIT ONLY: announcements.* (plural only)
if (
  action === 'announcements.markseen' ||
  action === 'announcements.dismiss'  ||
  action === 'announcements.restore'
) {
  const raw = e.parameter.payload || (e.postData && e.postData.contents) || '';
  if (!raw) return jsonError_('Missing payload', 400);

  const payload = JSON.parse(raw);

  const token = (e.parameter.token || payload.token || '').trim();
  if (!token) return jsonError_('Missing token', 400);

  const authInfo = verifyToken_(token);
  payload.user_id = authInfo.user_id;

  // Normalize item_id (allow announcement_id alias)
  if (!payload.item_id && payload.announcement_id) {
    payload.item_id = payload.announcement_id;
  }

  // markseen: normalize payload.items
  if (action === 'announcements.markseen') {
    let items = payload.items;

    // handle items coming as JSON string
    if (typeof items === 'string' && items.trim()) {
      try { items = JSON.parse(items); } catch(e) { items = [items]; }
    }

    if (!Array.isArray(items)) {
      if (payload.item_id) items = [payload.item_id];
      else items = [];
    }

    payload.items = items;
  }

  let out;
  if (action === 'announcements.markseen') out = announcementsMarkSeen_(payload);
  if (action === 'announcements.dismiss')  out = announcementsDismiss_(payload);
  if (action === 'announcements.restore')  out = announcementsRestore_(payload);

  return json_(out);
}



    // Fallback for unknown actions
    return jsonError_('Unknown action', 400);

  } catch (err) {
    return jsonError_(err.message || String(err), 500);
  }
}



/* ==================== CORE LOGIC — BUILDER ==================== */

// Returns {
//   course_id,
//   topics_main[],
//   difficulties[],
//   maxN,
//   total,
//   topic_counts:{ mainTopic -> total },
//   difficulty_counts:{ difficulty -> total },
//   topic_difficulty_counts: { mainTopic -> { difficulty -> count } },
//   concept_suggestions: [ "Gout", "Acute Gouty Arthritis", ... ],
//   concept_counts: { "Gout" -> total, "Acute Gouty Arthritis" -> total, ... }
// }
function getBuilderMeta_(courseId) {
  const sheetId = getCourseSheetId_(courseId);
  const items = readItems_(sheetId);

  const mainTopicSet = new Set();
  const diffSet = new Set();

  // counters
  const topicCounts = Object.create(null);         // main-topic -> count
  const difficultyCounts = Object.create(null);    // difficulty -> count (whole course)
  const topicDiffCounts = Object.create(null);     // main-topic -> { difficulty -> count }

  // concept suggestions from subtopics / topics
  const conceptSet = new Set();                    // unique concept strings
  const conceptCounts = Object.create(null);       // concept -> count

  items.forEach(r => {
    const topicRaw = String(r.topic || '').trim();
    const main = mainTopic_(topicRaw);             // e.g. "Gastrointestinal Surgery"
    const dRaw = String(r.difficulty || '').trim();// e.g. "Easy", "Moderate", "Hard"

    // ---- main topics + per-topic counts ----
    if (main) {
      const mainKey = String(main);
      mainTopicSet.add(mainKey);
      topicCounts[mainKey] = (topicCounts[mainKey] || 0) + 1;

      // per-topic difficulty counts
      if (dRaw) {
        if (!topicDiffCounts[mainKey]) {
          topicDiffCounts[mainKey] = Object.create(null);
        }
        topicDiffCounts[mainKey][dRaw] = (topicDiffCounts[mainKey][dRaw] || 0) + 1;
      }
    }

    // ---- global difficulty counts ----
    if (dRaw) {
      diffSet.add(dRaw);
      difficultyCounts[dRaw] = (difficultyCounts[dRaw] || 0) + 1;
    }

    // ---- concept suggestions (subtopics / topic text) + counts ----
    if (topicRaw) {
      const idx = topicRaw.indexOf(':');
      let concept = '';

      if (idx >= 0) {
        // part after colon = subtopic, e.g. "Gout", "Acute Gouty Arthritis"
        concept = topicRaw.slice(idx + 1).trim();
      } else {
        // no colon → treat whole topic as a concept, e.g. "Shock"
        concept = topicRaw;
      }

      if (concept) {
        conceptSet.add(concept);
        conceptCounts[concept] = (conceptCounts[concept] || 0) + 1;
      }
    }
  });

  const concept_suggestions = Array.from(conceptSet).sort(function(a, b) {
    return a.localeCompare(b);
  });

  return {
    course_id: courseId,
    topics_main: Array.from(mainTopicSet).sort(),
    difficulties: Array.from(diffSet).sort(),
    maxN: Math.min(items.length, MAX_N_DEFAULT),
    total: items.length,
    topic_counts: topicCounts,
    difficulty_counts: difficultyCounts,
    topic_difficulty_counts: topicDiffCounts,
    concept_suggestions: concept_suggestions,
    concept_counts: conceptCounts
  };
}


// Spawn attempt (Builder): filters by payload and samples up to n rows
// payload: {course_id, topics[], difficulties[], n, mode, source, duration_min?, user_id?, concept?, concepts?}
function spawnAttempt_(payload) {
  const courseId = must_(payload.course_id, 'payload.course_id required');
  const nReq     = clampInt_(payload.n || 10, 1, MAX_N_DEFAULT);
  const mode     = (payload.mode || 'instant').toLowerCase(); // 'instant' or 'timed'
  const topics   = Array.isArray(payload.topics) ? payload.topics : [];
  const diffs    = Array.isArray(payload.difficulties) ? payload.difficulties : [];

  // Concept mode v2:
  //  - payload.concepts[] = selected concept chips (multi-select)
  //  - payload.concept    = free-text global search (optional)
  const conceptQuery = String(payload.concept || '').toLowerCase().trim();

  const conceptChoices = Array.isArray(payload.concepts)
    ? payload.concepts
        .map(function(c){ return String(c || '').toLowerCase().trim(); })
        .filter(function(c){ return !!c; })
    : [];


  const sheetId  = getCourseSheetId_(courseId);
  const items    = readItems_(sheetId); // array of row objects

  // Filter pool
  let pool = items.filter(function(r) {
    // ----- Topic filter -----
    let topicOk = true;
    if (topics.length) {
      topicOk = topics.some(function(t) {
        if (String(t).indexOf(':') !== -1) {
          // exact subtopic match (if we ever use topic:subtopic form)
          return same_(r.topic, t);
        } else {
          // main-topic bucket
          return same_(mainTopic_(r.topic), t);
        }
      });
    }

    // ----- Difficulty filter -----
    let diffOk = true;
    if (diffs.length) {
      diffOk = diffs.some(function(d){ return same_(r.difficulty, d); });
    }

    // ----- Concept filter (v2) -----
    // 1) If conceptChoices[] selected → filter by those
    // 2) Else if conceptQuery typed → global search
    // 3) Else → no concept-based restriction
    let conceptOk = true;

    if (conceptChoices.length) {
      // For concept chips we can search topic + rationale (they’re concept-ish)
      const hay = (
        String(r.topic || '') + ' ' +
        String(r.rationale || '')
      ).toLowerCase();

      conceptOk = conceptChoices.some(function(c){
        return hay.indexOf(c) !== -1;
      });

    } else if (conceptQuery) {
      // Pure global search: topic + stem + rationale
      const hayGlobal = (
        String(r.topic || '') + ' ' +
        String(r.stem || '') + ' ' +
        String(r.rationale || '')
      ).toLowerCase();

      conceptOk = hayGlobal.indexOf(conceptQuery) !== -1;
    }

    return topicOk && diffOk && conceptOk;

  });

  if (pool.length === 0) {
    throw new Error('No items matched your filters.');
  }

  // Sample up to nReq without replacement
  const n    = Math.min(nReq, pool.length);
  const seed = makeSeed_();
  const sampled = sample_(pool, n, seed);

  // Decide duration_min (server-side, based on final n)
  const durationMin = (mode === 'timed')
    ? clampInt_(payload.duration_min || n, 1, 600)
    : '';

  const userId = String(payload.user_id || '').trim() || 'guest';

  // ---- Local helpers just for label building ----
  function canonicalDifficulty(d) {
    const s = norm_(d);
    if (s === 'easy') return 'Easy';
    if (s === 'moderate' || s === 'medium') return 'Moderate';
    if (s === 'hard' || s === 'difficult') return 'Hard';
    return '';
  }

  function buildBuilderDisplayLabel(topicsArr, diffsArr, nQuestions) {
    topicsArr = Array.isArray(topicsArr) ? topicsArr : [];
    diffsArr  = Array.isArray(diffsArr)  ? diffsArr  : [];

    // ----- TopicPart -----
    const mainSet = new Set();
    topicsArr.forEach(function(t) {
      const main = mainTopic_(t);
      if (main) mainSet.add(main);
    });
    const mains = Array.from(mainSet).sort(function(a, b) {
      return a.localeCompare(b);
    });

    let topicPart;
    if (!mains.length) {
      // No explicit topics selected → treat as full bank / mixed
      topicPart = 'Full bank';
    } else if (mains.length === 1) {
      topicPart = mains[0];
    } else if (mains.length === 2) {
      topicPart = mains[0] + ' & ' + mains[1];
    } else if (mains.length === 3) {
      topicPart = mains[0] + ', ' + mains[1] + ' & ' + mains[2];
    } else {
      topicPart = 'Mixed topics';
    }

    // ----- DiffPart -----
    const order = ['Easy', 'Moderate', 'Hard'];
    const canon = [];
    diffsArr.forEach(function(d) {
      const c = canonicalDifficulty(d);
      if (c && canon.indexOf(c) < 0) canon.push(c);
    });
    canon.sort(function(a, b) {
      return order.indexOf(a) - order.indexOf(b);
    });

    let diffPart;
    if (!canon.length || canon.length === order.length) {
      diffPart = 'Mixed';
    } else if (canon.length === 1) {
      diffPart = canon[0] + ' only';
    } else if (canon.length === 2) {
      diffPart = canon[0] + '+' + canon[1];
    } else {
      diffPart = 'Mixed';
    }

    const safeN = nQuestions || 0;
    return 'Custom - ' + topicPart + ' (' + diffPart + ', ' + safeN + 'Q)';
  }

  // Build human-friendly label for this builder attempt
  const displayLabel = buildBuilderDisplayLabel(topics, diffs, n);

  // Persist attempt (initially in_progress)
  const attemptId = 'ATT_' + Utilities.getUuid().replace(/-/g, '').slice(0, 24);
  writeAttemptRow_({
    attempt_id:     attemptId,
    ts_iso:         new Date().toISOString(),
    course_id:      courseId,
    mode:           mode,
    duration_min:   durationMin,
    user_id:        userId,
    n:              n,
    seed:           seed,
    source:         payload.source || 'builder',
    item_ids:       sampled.map(function(r){ return r.item_id; }).join(','),
    quiz_id:        '',                 // builder attempts have no quiz_id
    display_label:  displayLabel,       // key for History/Review UI
    status:         'in_progress'       // NEW: mark as in_progress at spawn
    // scores, answers_json, etc. filled later by attempt.update / attempt.finish
  });

  return { attempt_id: attemptId, n: n, mode: mode, seed: seed, duration_min: durationMin };
}



// Returns full hydrated attempt: { meta, items[] }
// options (all optional, for stronger security when provided):
//   - token: string (qa_token from browser)
//   - expectedMode: 'instant' | 'timed'
//   - expectedCourseId: course_id string
function getAttempt_(attemptId, options) {
  options = options || {};
  const token            = (options.token            || '').toString().trim();
  const expectedMode     = (options.expectedMode     || '').toString().trim().toLowerCase();
  const expectedCourseId = (options.expectedCourseId || '').toString().trim();

  const att = readAttemptRow_(attemptId);
  if (!att) throw new Error('Attempt not found');

  // --- 1) Ownership check via token (if provided) ---
  // We don't trust any user_id coming from the browser; we trust the token.
  if (token) {
    const authInfo        = verifyToken_(token); // uses TAB_TOKENS + TAB_USERS
    const userIdFromToken = String(authInfo.user_id || '').trim();
    const ownerId         = String(att.user_id      || '').trim();

    if (ownerId && userIdFromToken && ownerId !== userIdFromToken) {
      throw new Error('Attempt does not belong to this user');
    }
  }

  // --- 2) Course match (if caller says which course it expects) ---
  if (expectedCourseId) {
    if (!same_(att.course_id, expectedCourseId)) {
      throw new Error('Attempt is for a different course');
    }
  }

  // --- 3) Mode match (if caller declares which mode it expects) ---
  if (expectedMode) {
    const modeNorm = norm_(att.mode || '');
    if (modeNorm && modeNorm !== expectedMode) {
      throw new Error('Attempt was created for a different mode');
    }
  }

  // --- 4) Normal hydration (also enforces course is active via getCourseSheetId_) ---
  const sheetId = getCourseSheetId_(att.course_id);
  const items   = readItems_(sheetId);

  const wanted = (att.item_ids || '')
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);

  const mapById = new Map(items.map(r => [String(r.item_id), r]));

  const hydrated = wanted.map(function(id) {
    const r = mapById.get(id);
    if (!r) return null; // tolerate missing
    return r;
  }).filter(Boolean);

  let answers = [];
  if (att.answers_json) {
    try {
      const parsed = JSON.parse(att.answers_json);
      if (Array.isArray(parsed)) answers = parsed;
    } catch (err) {
      answers = [];
    }
  }

  return {
    meta: {
      attempt_id:        att.attempt_id,
      course_id:         att.course_id,
      mode:              att.mode,
      n:                 hydrated.length,
      duration_min:      att.duration_min || '',
      user_id:           att.user_id || '',
      source:            att.source || '',
      quiz_id:           att.quiz_id || '',
      ts_iso:            att.ts_iso,
      status:            att.status || '',
      score_raw:         att.score_raw || '',
      score_total:       att.score_total || '',
      score_pct:         att.score_pct || '',
      time_taken_s:      att.time_taken_s || '',
      origin_attempt_id: att.origin_attempt_id || '',
      answers:           answers
    },
    items: hydrated
  };
}



/* ==================== CORE LOGIC — FIXED QUIZZES ==================== */

// GET: courseQuizzes — list visible quizzes for a course
// Returns: { course_id, quizzes: [ {quiz_id, title, type, n, status, publish_at, unpublish_at} ] }
function getCourseQuizzes_(courseId) {
  const all = readQuizzes_(); // array of quiz row objects
  const now = new Date();

  const filtered = all.filter(q => {
    if (!same_(q.course_id, courseId)) return false;
    // Must be published
    if (!isTruthy_(q.published)) return false;
    // Must not be hidden
    if (same_(q.visibility, 'hidden')) return false;
    return true;
  });

  const quizzes = filtered.map(q => {
    const status = computeQuizStatus_(q, now); // UPCOMING / ACTIVE / CLOSED
    return {
      quiz_id: q.quiz_id,
      course_id: q.course_id,
      title: q.title || '',
      type: q.type || '',           // INSTANT / TIMED (as in quizzes tab)
      n: q.n || '',                 // optional stored number of questions
      status: status,
      publish_at: q.publish_at || '',
      unpublish_at: q.unpublish_at || ''
    };
  });

  return { course_id: courseId, quizzes: quizzes };
}

// POST: fixed.spawn — create attempt for a fixed quiz
// payload: {quiz_id, user_id?, source?}
function spawnFixedAttempt_(payload) {
  const quizId = must_(payload.quiz_id, 'payload.quiz_id required');
  const userId = String(payload.user_id || '').trim() || 'guest';
  const all = readQuizzes_();
  const now = new Date();
    // ✅ If user already has an in-progress attempt for this fixed quiz, reuse it
  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  const existing = findInProgressAttemptForFixedQuiz_(ss, userId, quizId);
  if (existing) {
    return {
      attempt_id: existing.attempt_id,
      mode: existing.mode || '',
      n: existing.n || '',
      duration_min: existing.duration_min || '',
      reused: true
    };
  }


  const quiz = all.find(q => same_(q.quiz_id, quizId));
  if (!quiz) {
    throw new Error('Quiz not found: ' + quizId);
  }

  // Enforce availability (publish, visibility, status)
  if (!isTruthy_((quiz.published))) {
    throw new Error('Quiz is not published');
  }
  if (same_(quiz.visibility, 'hidden')) {
    throw new Error('Quiz is hidden');
  }
  const status = computeQuizStatus_(quiz, now);
  if (status !== 'ACTIVE') {
    throw new Error('Quiz is not currently active (' + status + ')');
  }

  const courseId = must_(quiz.course_id, 'quiz.course_id missing');
  const typeRaw  = String(quiz.type || '').toUpperCase();
  const mode     = (typeRaw === 'TIMED') ? 'timed' : 'instant'; // map quizzes.type -> attempts.mode

  const sheetId  = getCourseSheetId_(courseId);
  const items    = readItems_(sheetId);

  // Determine which column to use for grouping items for this quiz
  const groupKey = (typeRaw === 'TIMED') ? 'timed_id' : 'instant_id';

  const pool = items.filter(r => same_(r[groupKey], quizId));
  if (!pool.length) {
    throw new Error('No items found for this quiz');
  }

  // Fixed order: keep sheet order (no shuffling)
  const itemIds = pool.map(r => r.item_id);
  const n = itemIds.length;

  // Duration: for timed mode, use configured duration_min if present, else n
  let durationMin = '';
  if (mode === 'timed') {
    const quizDur = quiz.duration_min;
    if (quizDur !== undefined && quizDur !== null && String(quizDur).trim() !== '') {
      durationMin = clampInt_(quizDur, 1, 600);
    } else {
      durationMin = clampInt_(n, 1, 600);
    }
  }

  const attemptId = 'ATT_' + Utilities.getUuid().replace(/-/g, '').slice(0, 24);
  writeAttemptRow_({
    attempt_id:     attemptId,
    ts_iso:         new Date().toISOString(),
    course_id:      courseId,
    mode:           mode,
    duration_min:   durationMin,
    user_id:        userId,
    n:              n,
    seed:           makeSeed_(),
    source:         payload.source || 'fixed',
    item_ids:       itemIds.join(','),
    quiz_id:        quizId,                // link attempt → fixed quiz
    display_label:  quiz.title || '',      // human title for History/Review
    status:         'in_progress'          // NEW: mark as in_progress at spawn
    // scores, answers_json, etc. filled later by attempt.update / attempt.finish
  });

  return {
    attempt_id: attemptId,
    mode: mode,
    n: n,
    duration_min: durationMin
  };
}


/* ==================== SHEET HELPERS ==================== */

function getCourseSheetId_(courseId) {
  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  const sh = ss.getSheetByName(TAB_COURSES);
  if (!sh) throw new Error(`Missing "${TAB_COURSES}" tab in Portal DB`);
  const values = sh.getDataRange().getValues();
  if (!values.length) throw new Error('Empty courses table');

  const header = values[0].map(s => String(s).trim().toLowerCase());
  const rCourse = colIndex_(header, 'course_id');
  const rSheet  = colIndex_(header, 'sheet_id');
  const rStatus = colIndex_(header, 'status');

  for (let i = 1; i < values.length; i++) {
    const row = values[i];
    const cId = String(row[rCourse]).trim();
    if (same_(cId, courseId)) {
      const status = String(row[rStatus] || '').toLowerCase();
      if (status && status !== 'active') {
        throw new Error(`Course "${courseId}" is not active`);
      }
      const sid = String(row[rSheet]).trim();
      if (!sid) throw new Error(`No sheet_id for course "${courseId}"`);
      return sid;
    }
  }
  throw new Error(`Course not found: ${courseId}`);
}

function listActiveCourses_() {
  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  const sh = ss.getSheetByName(TAB_COURSES);
  if (!sh) throw new Error(`Missing "${TAB_COURSES}" tab`);
  const values = sh.getDataRange().getValues();
  if (values.length < 2) return [];

  const header = values[0].map(s => String(s).trim().toLowerCase());
  const iCourse = header.indexOf('course_id');
  const iStatus = header.indexOf('status');

  const out = [];
  for (let r = 1; r < values.length; r++) {
    const row = values[r];
    const course = String(row[iCourse] || '').trim();
    const status = String(row[iStatus] || '').trim().toLowerCase();
    if (!course) continue;
    if (status && status !== 'active') continue; // only active or blank
    out.push(course);
  }
  return out;
}

function readItems_(sheetId) {
  const ss = SpreadsheetApp.openById(sheetId);
  const sh = ss.getSheetByName('items');
  if (!sh) throw new Error('Missing "items" tab');
  const values = sh.getDataRange().getValues();
  if (values.length < 2) return [];

  const header = values[0].map(s => String(s).trim().toLowerCase());

  // Expected columns (case-insensitive):
  // item_id, stem, option_a, fb_a, option_b, fb_b, option_c, fb_c, option_d, fb_d,
  // correct, rationale, rationale_img, subject, topic, difficulty, marks,
  // instant_id?, timed_id?
  const idx = Object.fromEntries([
    'item_id','stem','option_a','fb_a','option_b','fb_b','option_c','fb_c','option_d','fb_d',
    'correct','rationale','rationale_img','subject','topic','difficulty','marks',
    'instant_id','timed_id'
  ].map(k => [k, colIndexOptional_(header, k)]));

  const out = [];
  for (let i = 1; i < values.length; i++) {
    const row = values[i];
    const obj = {
      item_id:       getCell_(row, idx.item_id),
      stem:          getCell_(row, idx.stem),
      option_a:      getCell_(row, idx.option_a),
      fb_a:          getCell_(row, idx.fb_a),
      option_b:      getCell_(row, idx.option_b),
      fb_b:          getCell_(row, idx.fb_b),
      option_c:      getCell_(row, idx.option_c),
      fb_c:          getCell_(row, idx.fb_c),
      option_d:      getCell_(row, idx.option_d),
      fb_d:          getCell_(row, idx.fb_d),
      correct:       getCell_(row, idx.correct),
      rationale:     getCell_(row, idx.rationale),
      rationale_img: getCell_(row, idx.rationale_img),  // 🔹 NEW FIELD
      subject:       getCell_(row, idx.subject),
      topic:         getCell_(row, idx.topic),
      difficulty:    getCell_(row, idx.difficulty),
      marks:         getCell_(row, idx.marks)
    };

    // Optional grouping columns for fixed quizzes
    if (idx.instant_id >= 0) obj.instant_id = getCell_(row, idx.instant_id);
    if (idx.timed_id   >= 0) obj.timed_id   = getCell_(row, idx.timed_id);

    out.push(obj);
  }
  return out.filter(r => r.item_id); // require item_id
}


// Append a new attempt row (used by builder.spawn and fixed.spawn)
function writeAttemptRow_(rowObj) {
  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  let sh = ss.getSheetByName(TAB_ATTEMPTS);

  // Create sheet and header if missing
  if (!sh) {
    sh = ss.insertSheet(TAB_ATTEMPTS);
    sh.appendRow(ATTEMPTS_DEFAULT_HEADER);
  }

  // Current header row (lowercased)
  let header = sh.getRange(1, 1, 1, sh.getLastColumn())
    .getValues()[0]
    .map(s => String(s).trim().toLowerCase());

  // Ensure all expected columns exist
  const needed = ATTEMPTS_DEFAULT_HEADER.filter(h => header.indexOf(h) < 0);
  if (needed.length) {
    sh.insertColumnsAfter(header.length || 1, needed.length);
    header = header.concat(needed);
    sh.getRange(1, 1, 1, header.length).setValues([header]);
  }

  // Build row aligned to header by name
  const row = header.map(h => (h in rowObj) ? rowObj[h] : '');
  sh.appendRow(row);
}


function readAttemptRow_(attemptId) {
  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  const sh = ss.getSheetByName(TAB_ATTEMPTS);
  if (!sh) return null;
  const values = sh.getDataRange().getValues();
  if (values.length < 2) return null;

  const header = values[0].map(s => String(s).trim().toLowerCase());
  const H = {}; header.forEach((h, i) => H[h] = i);

  const idCol = H['attempt_id'];
  if (idCol == null) return null;

  for (let i = 1; i < values.length; i++) {
    const row = values[i];
    if (same_(row[idCol], attemptId)) {
      return {
        attempt_id:        row[H.attempt_id],
        ts_iso:            row[H.ts_iso],
        course_id:         row[H.course_id],
        mode:              row[H.mode],
        duration_min:      (H.duration_min      != null ? row[H.duration_min]      : ''),
        user_id:           (H.user_id           != null ? row[H.user_id]           : ''),
        n:                 row[H.n],
        seed:              row[H.seed],
        source:            row[H.source],
        item_ids:          row[H.item_ids],
        quiz_id:           (H.quiz_id           != null ? row[H.quiz_id]           : ''),
        display_label:     (H.display_label     != null ? row[H.display_label]     : ''),
        status:            (H.status            != null ? row[H.status]            : ''),
        score_raw:         (H.score_raw         != null ? row[H.score_raw]         : ''),
        score_total:       (H.score_total       != null ? row[H.score_total]       : ''),
        score_pct:         (H.score_pct         != null ? row[H.score_pct]         : ''),
        time_taken_s:      (H.time_taken_s      != null ? row[H.time_taken_s]      : ''),
        answers_json:      (H.answers_json      != null ? row[H.answers_json]      : ''),
        origin_attempt_id: (H.origin_attempt_id != null ? row[H.origin_attempt_id] : '')
      };
    }
  }
  return null;
}


/* ==================== attempt.finish & attempt.update HELPERS ==================== */

// POST: attempt.finish — write back score + timing + answers
// payload: {attempt_id, user_id?, score_raw, score_total, score_pct?, time_taken_s?, answers:[]}
function finishAttempt_(payload) {
  const attemptId = must_(payload.attempt_id, 'payload.attempt_id required');

  // Basic numeric parsing
  const scoreRaw   = clampInt_(payload.score_raw,   0, 1000000);
  const scoreTotal = clampInt_(payload.score_total, 1, 1000000);
  const scorePct   = Math.round((scoreRaw * 100) / scoreTotal);
  const timeTaken  = clampInt_(payload.time_taken_s || 0, 0, 86400); // cap at 24h

  const answersArr  = Array.isArray(payload.answers) ? payload.answers : [];
  const answersJson = JSON.stringify(answersArr);

  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  let sh = ss.getSheetByName(TAB_ATTEMPTS);
  if (!sh) throw new Error('Attempts table not found');

  // Ensure header has all expected columns
  let header = sh.getRange(1, 1, 1, sh.getLastColumn())
    .getValues()[0]
    .map(s => String(s).trim().toLowerCase());

  const needed = ATTEMPTS_DEFAULT_HEADER.filter(h => header.indexOf(h) < 0);
  if (needed.length) {
    sh.insertColumnsAfter(header.length || 1, needed.length);
    header = header.concat(needed);
    sh.getRange(1, 1, 1, header.length).setValues([header]);
  }

  const H = {};
  header.forEach((h, i) => H[h] = i);

  const idCol = H['attempt_id'];
  if (idCol == null) throw new Error('Missing attempt_id column');

  const lastRow = sh.getLastRow();
  if (lastRow < 2) throw new Error('No attempts found');

  // Find the row for this attempt_id
  const dataRange = sh.getRange(2, 1, lastRow - 1, header.length);
  const values = dataRange.getValues();
  let rowIndex = -1; // sheet row index (1-based)

  for (let r = 0; r < values.length; r++) {
    const row = values[r];
    if (same_(row[idCol], attemptId)) {
      rowIndex = r + 2; // +2 because data starts at row 2
      break;
    }
  }

  if (rowIndex < 0) {
    throw new Error('Attempt not found');
  }

  // Check if already completed
  const statusCol = H['status'];
  let existingStatus = '';
  if (statusCol != null) {
    existingStatus = String(sh.getRange(rowIndex, statusCol + 1).getValue() || '');
  }
  if (norm_(existingStatus) === 'completed') {
    throw new Error('Attempt already completed');
  }

  // Load full row to update in-memory then write back once
  const rowVals = sh.getRange(rowIndex, 1, 1, header.length).getValues()[0];

  function setField(key, value) {
    const c = H[key];
    if (c != null) rowVals[c] = value;
  }

  setField('status',        'completed');
  setField('score_raw',     scoreRaw);
  setField('score_total',   scoreTotal);
  setField('score_pct',     scorePct);
  setField('time_taken_s',  timeTaken);
  setField('answers_json',  answersJson);

  sh.getRange(rowIndex, 1, 1, header.length).setValues([rowVals]);

  // Response back to runner
  return {
    ok:            true,
    attempt_id:    attemptId,
    status:        'completed',
    score_raw:     scoreRaw,
    score_total:   scoreTotal,
    score_pct:     scorePct,
    time_taken_s:  timeTaken
  };
}

// POST: attempt.update — partial save while attempt is in_progress
// payload: {attempt_id, answers:[], time_taken_s?}
function updateAttempt_(payload) {
  const attemptId = must_(payload.attempt_id, 'payload.attempt_id required');

  const answersArr  = Array.isArray(payload.answers) ? payload.answers : [];
  const answersJson = JSON.stringify(answersArr);
  const timeTaken   = (payload.time_taken_s != null)
    ? clampInt_(payload.time_taken_s, 0, 86400)
    : null;

  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  let sh = ss.getSheetByName(TAB_ATTEMPTS);
  if (!sh) throw new Error('Attempts table not found');

  // Ensure header has all expected columns
  let header = sh.getRange(1, 1, 1, sh.getLastColumn())
    .getValues()[0]
    .map(s => String(s).trim().toLowerCase());

  const needed = ATTEMPTS_DEFAULT_HEADER.filter(h => header.indexOf(h) < 0);
  if (needed.length) {
    sh.insertColumnsAfter(header.length || 1, needed.length);
    header = header.concat(needed);
    sh.getRange(1, 1, 1, header.length).setValues([header]);
  }

  const H = {};
  header.forEach((h, i) => H[h] = i);

  const idCol = H['attempt_id'];
  if (idCol == null) throw new Error('Missing attempt_id column');

  const lastRow = sh.getLastRow();
  if (lastRow < 2) throw new Error('No attempts found');

  const dataRange = sh.getRange(2, 1, lastRow - 1, header.length);
  const values = dataRange.getValues();
  let rowIndex = -1; // sheet row index (1-based)

  for (let r = 0; r < values.length; r++) {
    const row = values[r];
    if (same_(row[idCol], attemptId)) {
      rowIndex = r + 2; // +2 because data starts at row 2
      break;
    }
  }

  if (rowIndex < 0) {
    throw new Error('Attempt not found');
  }

  // Load full row for in-memory update
  const rowVals = sh.getRange(rowIndex, 1, 1, header.length).getValues()[0];

  const statusCol = H['status'];
  let existingStatus = '';
  if (statusCol != null) {
    existingStatus = String(rowVals[statusCol] || '');
  }

  // If already completed, do NOT allow partial updates
  if (norm_(existingStatus) === 'completed') {
    throw new Error('Attempt already completed');
  }

  function setField(key, value) {
    const c = H[key];
    if (c != null) rowVals[c] = value;
  }

  // Keep / enforce in_progress
  if (!existingStatus) {
    setField('status', 'in_progress');
  }

  // Update answers_json snapshot
  setField('answers_json', answersJson);

  // Optional: update time_taken_s if provided
  if (timeTaken !== null) {
    setField('time_taken_s', timeTaken);
  }

  sh.getRange(rowIndex, 1, 1, header.length).setValues([rowVals]);

  return {
    ok:           true,
    attempt_id:   attemptId,
    status:       existingStatus || 'in_progress'
  };
}

// POST: attempt.retake — spawn a NEW attempt with the same item_ids
// payload: {attempt_id, user_id?}
function retakeAttempt_(payload) {
  const originalAttemptId = must_(payload.attempt_id, 'payload.attempt_id required');
  const requestUserId = String(payload.user_id || '').trim(); // from frontend

  // 1) Load original attempt
  const original = readAttemptRow_(originalAttemptId);
  if (!original) {
    throw new Error('Original attempt not found');
  }

  // 2) Enforce user ownership (if provided)
  const ownerId = String(original.user_id || '').trim();
  if (requestUserId && ownerId && ownerId !== requestUserId) {
    throw new Error('Attempt does not belong to this user');
  }

  // 3) Require item_ids
  const itemIdsArr = String(original.item_ids || '')
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);

  if (!itemIdsArr.length) {
    throw new Error('Original attempt has no items to retake');
  }

  // 4) Only allow retake for completed attempts (business rule)
  const statusNorm = norm_(original.status || '');
  if (statusNorm !== 'completed') {
    throw new Error('Only completed attempts can be retaken');
  }

  // 5) Decide duration for the new attempt
  const n = itemIdsArr.length;
  let durationMin = '';

  if (norm_(original.mode) === 'timed') {
    if (original.duration_min !== undefined && original.duration_min !== null && String(original.duration_min).trim() !== '') {
      durationMin = clampInt_(original.duration_min, 1, 600);
    } else {
      durationMin = clampInt_(n, 1, 600);
    }
  }

  // 6) Build new attempt row
  const newAttemptId = 'ATT_' + Utilities.getUuid().replace(/-/g, '').slice(0, 24);

  writeAttemptRow_({
    attempt_id:        newAttemptId,
    ts_iso:            new Date().toISOString(),
    course_id:         original.course_id,
    mode:              original.mode,
    duration_min:      durationMin,
    user_id:           ownerId || requestUserId || 'guest',
    n:                 n,
    seed:              makeSeed_(),
    source:            original.source || 'builder',   // keep same source (builder/fixed)
    item_ids:          itemIdsArr.join(','),
    quiz_id:           original.quiz_id || '',         // preserves link for fixed quizzes
    display_label:     original.display_label || '',   // same label in history
    status:            'in_progress',
    origin_attempt_id: original.attempt_id             // link back to original
    // scores + answers_json start empty
  });

  return {
    ok:           true,
    attempt_id:   newAttemptId,
    mode:         original.mode || '',
    n:            n,
    duration_min: durationMin
  };
}


/* ==================== attempts.list HELPER ==================== */

// GET: attempts.list — list attempts for a user (with optional filters)
// filters: {user_id, course_id?, mode?, source?, status?}
// Returns: { attempts:[...], summary:{count, avg_pct, instant_count, timed_count} }
function listAttempts_(filters) {
  const userId   = String(filters.user_id || '').trim();
  if (!userId) throw new Error('user_id required');

  const courseId = String(filters.course_id || '').trim().toLowerCase();
  const mode     = String(filters.mode     || '').trim().toLowerCase();
  const source   = String(filters.source   || '').trim().toLowerCase();
  const status   = String(filters.status   || '').trim().toLowerCase();

  const ss = SpreadsheetApp.openById(PORTAL_DB_ID);
  const sh = ss.getSheetByName(TAB_ATTEMPTS);
  if (!sh) {
    return { attempts: [], summary: { count: 0, avg_pct: 0, instant_count: 0, timed_count: 0 } };
  }

  const values = sh.getDataRange().getValues();
  if (values.length < 2) {
    return { attempts: [], summary: { count: 0, avg_pct: 0, instant_count: 0, timed_count: 0 } };
  }

  const header = values[0].map(s => String(s).trim().toLowerCase());
  const H = {}; header.forEach((h, i) => H[h] = i);

  function cell(row, key) {
    const idx = H[key];
    return (idx != null) ? row[idx] : '';
  }

  const attempts = [];
  let countScored = 0;
  let sumPct = 0;
  let instantCount = 0;
  let timedCount   = 0;

  for (let r = 1; r < values.length; r++) {
    const row = values[r];

    // Filter by user_id
    const uid = String(cell(row, 'user_id') || '').trim();
    if (!uid || uid !== userId) continue;

    const cId  = String(cell(row, 'course_id') || '').trim().toLowerCase();
    const mRaw = String(cell(row, 'mode')      || '').trim().toLowerCase();
    const sRaw = String(cell(row, 'source')    || '').trim().toLowerCase();
    const st   = String(cell(row, 'status')    || '').trim().toLowerCase();

    if (courseId && cId !== courseId) continue;
    if (mode     && mRaw !== mode)     continue;
    if (source   && sRaw !== source)   continue;
    if (status   && st   !== status)   continue;

    const scoreRaw   = Number(cell(row, 'score_raw')   || 0);
    const scoreTotal = Number(cell(row, 'score_total') || 0);
    const scorePct   = Number(cell(row, 'score_pct')   || 0);
    const modeNorm   = mRaw || '';

    const att = {
      attempt_id:    String(cell(row, 'attempt_id')    || ''),
      ts_iso:        String(cell(row, 'ts_iso')        || ''),
      course_id:     String(cell(row, 'course_id')     || ''),
      quiz_id:       String(cell(row, 'quiz_id')       || ''),
      display_label: String(cell(row, 'display_label') || ''),
      mode:          modeNorm,
      source:        sRaw || '',
      status:        st || '',
      n:             Number(cell(row, 'n') || 0),
      duration_min:  cell(row, 'duration_min') || '',
      score_raw:     scoreRaw,
      score_total:   scoreTotal,
      score_pct:     scorePct,
      time_taken_s:  Number(cell(row, 'time_taken_s') || 0)
    };

    attempts.push(att);

    // Summary stats (only count attempts that have a pct)
    if (scorePct > 0) {
      countScored += 1;
      sumPct += scorePct;
    }
    if (modeNorm === 'instant') instantCount += 1;
    if (modeNorm === 'timed')   timedCount   += 1;
  }

  const avgPct = countScored ? Math.round(sumPct / countScored) : 0;

  return {
    attempts: attempts,
    summary: {
      count:          attempts.length, // total attempts returned (not just scored)
      avg_pct:        avgPct,
      instant_count:  instantCount,
      timed_count:    timedCount
    }
  };
}


